function COMPUTE_WITH_CHECK(input):
    # Step 1: Compute the result
    result = SERENAL_EQUATION(input)

    # Step 2: Check for Null-Variance
    if C(result.S) != 0:
        return NULL_VIOLATION("Center encoding violated")

    if result.Sigma < 0 or result.Sigma > 3.0:
        return NULL_VIOLATION("Sigma out of bounds")

    if result.Omega < 0 or result.Omega > 1:
        return NULL_VIOLATION("Omega out of bounds")

    if result.Lambda < 0:
        return NULL_VIOLATION("Negative gold density")

    if is_nan(result) or is_inf(result):
        return NULL_VIOLATION("NaN or infinity detected")

    # Step 3: Return valid result
    return result

function NULL_VIOLATION(message):
    log_error(message)
    trigger_recalibration()
    return NV
